/* 1. 【核心】为右侧面板设定固定的、合理的最大宽度和位置 */
#right-nav-panel.drawer-content {
    max-width: 500px !important; /* 您可以微调这个数值，500px 是一个比较舒适的宽度 */
    min-width: 420px !important;
    width: 35vw !important;      /* 使用视口宽度的35% */

    right: 0 !important;
    left: auto !important; /* 确保 left 定位无效 */
    transform: none !important; /* 移除任何可能导致偏移的 transform */

    /* 确保内部内容可以滚动 */
    overflow-x: hidden !important; 
    overflow-y: auto !important;
}

